//+------------------------------------------------------------------+
//|                                        Weinstein_Stage_EA.mq5    |
//|                       Basado en Stage Analysis de Stan Weinstein  |
//|                                                                  |
//|  REALIDAD: Esto es un sistema de trend-following con SMA 200     |
//|  + filtros de volumen y momentum. Funciona mejor en commodities  |
//|  (XAUUSD, WTI) en D1. Aceptable en índices. Débil en forex.     |
//|                                                                  |
//|  NO es el sistema completo de Weinstein (eso requiere            |
//|  discrecionalidad humana). Es la parte cuantificable (~80%).     |
//|                                                                  |
//|  Expectativa realista: Win rate 35-45%, Reward:Risk 2:1-3:1,     |
//|  Profit Factor 1.3-1.8, Drawdown 15-25%.                        |
//+------------------------------------------------------------------+
#property copyright   "Jose - Weinstein Stage Analysis EA"
#property link        ""
#property version     "1.00"
#property description "Trend-following basado en Análisis por Etapas de Weinstein"
#property description "Activo primario: XAUUSD D1 | Compatible: Commodities, Índices"
#property description "NO optimizar parámetros agresivamente - buscar mesetas estables"

#include <Trade\Trade.mqh>
#include <Trade\PositionInfo.mqh>
#include <Trade\SymbolInfo.mqh>

//+------------------------------------------------------------------+
//| ENUMERACIONES                                                     |
//+------------------------------------------------------------------+
enum ENUM_STAGE
  {
   STAGE_UNDEFINED = 0,    // Indefinido
   STAGE_1_ACCUMULATION,   // Etapa 1 - Acumulación (base lateral)
   STAGE_2_ADVANCING,      // Etapa 2 - Avance (SOLO aquí se compra)
   STAGE_3_DISTRIBUTION,   // Etapa 3 - Distribución (preparar salida)
   STAGE_4_DECLINING       // Etapa 4 - Declive (SOLO aquí se vende corto)
  };

enum ENUM_DIRECTION_MODE
  {
   MODE_LONG_ONLY = 0,     // Solo Longs (recomendado - genera ~90% de las ganancias)
   MODE_BOTH_DIRECTIONS,   // Ambas direcciones (shorts al 50% del tamaño)
   MODE_SHORT_ONLY         // Solo Shorts (NO recomendado - edge negativo a largo plazo)
  };

//+------------------------------------------------------------------+
//| INPUTS - PARÁMETROS DEL EA                                        |
//+------------------------------------------------------------------+

//--- Configuración principal
input group "══════ CONFIGURACIÓN PRINCIPAL ══════"
input int         InpMAPeriod        = 200;    // Período de la SMA (200 = estándar Weinstein)
input int         InpMAFastPeriod    = 50;     // SMA rápida (filtro Golden/Death Cross)
input ENUM_TIMEFRAMES InpTimeframe   = PERIOD_D1; // Temporalidad (D1 recomendado)
input ENUM_DIRECTION_MODE InpDirection = MODE_LONG_ONLY; // Dirección de operación
input int         InpMagicNumber     = 202603; // Número mágico

//--- Filtros de entrada
input group "══════ FILTROS DE ENTRADA ══════"
input int         InpSlopePeriod     = 20;     // Barras para calcular pendiente de MA (20-40)
input double      InpMinSlope        = 0.001;  // Pendiente mínima de MA para confirmar tendencia
input int         InpADXPeriod       = 14;     // Período ADX
input double      InpADXMinLevel     = 20.0;   // ADX mínimo para confirmar tendencia
input double      InpVolMultiplier   = 1.5;    // Multiplicador de volumen vs promedio (Weinstein: 2x)
input int         InpVolAvgPeriod    = 20;     // Período para promedio de volumen
input bool        InpRequireGoldenCross = true; // Requerir MA50 > MA200 para longs

//--- Gestión de riesgo
input group "══════ GESTIÓN DE RIESGO ══════"
input double      InpRiskPercent     = 1.0;    // % de capital por operación (1-2% recomendado)
input double      InpATRMultiplier   = 2.5;    // Multiplicador ATR para stop loss
input int         InpATRPeriod       = 14;     // Período ATR
input double      InpMaxDrawdownPct  = 15.0;   // Drawdown máximo permitido (% de balance inicial)
input double      InpShortSizeRatio  = 0.5;    // Ratio de tamaño para shorts (0.5 = 50% del largo)
input int         InpMaxOpenTrades   = 3;      // Máximo de operaciones abiertas simultáneas

//--- Trailing stop
input group "══════ TRAILING STOP ══════"
input bool        InpUseTrailingStop = true;   // Usar trailing stop
input double      InpTrailATRMult    = 2.0;    // Multiplicador ATR para trailing
input bool        InpTrailUseMA      = true;   // Usar MA como trailing (más conservador)

//--- Horarios (relevante para CFDs)
input group "══════ FILTRO HORARIO ══════"
input bool        InpUseTimeFilter   = false;  // Usar filtro horario
input int         InpStartHour       = 8;      // Hora inicio operaciones (servidor)
input int         InpEndHour         = 20;     // Hora fin operaciones (servidor)

//+------------------------------------------------------------------+
//| VARIABLES GLOBALES                                                |
//+------------------------------------------------------------------+
CTrade         m_trade;
CPositionInfo  m_position;
CSymbolInfo    m_symbol;

// Handles de indicadores
int            h_MA_slow;        // SMA 200
int            h_MA_fast;        // SMA 50
int            h_ADX;            // ADX
int            h_ATR;            // ATR

// Estado del sistema
ENUM_STAGE     g_currentStage;   // Etapa actual detectada
ENUM_STAGE     g_prevStage;      // Etapa anterior
double         g_initialBalance; // Balance al iniciar
datetime       g_lastBarTime;    // Para detectar nueva barra
bool           g_isNewBar;       // Flag de nueva barra

// Buffers
double         g_maSlowBuf[];
double         g_maFastBuf[];
double         g_adxBuf[];
double         g_atrBuf[];

//+------------------------------------------------------------------+
//| Expert initialization function                                    |
//+------------------------------------------------------------------+
int OnInit()
  {
//--- Validaciones básicas
   if(InpMAPeriod < 50 || InpMAPeriod > 300)
     {
      Print("ERROR: Período MA debe estar entre 50 y 300. Valor: ", InpMAPeriod);
      return(INIT_PARAMETERS_INCORRECT);
     }

   if(InpRiskPercent <= 0 || InpRiskPercent > 5.0)
     {
      Print("ERROR: Riesgo por trade debe estar entre 0.01% y 5%. Valor: ", InpRiskPercent);
      return(INIT_PARAMETERS_INCORRECT);
     }

   if(InpATRMultiplier < 1.0 || InpATRMultiplier > 5.0)
     {
      Print("ERROR: Multiplicador ATR debe estar entre 1.0 y 5.0. Valor: ", InpATRMultiplier);
      return(INIT_PARAMETERS_INCORRECT);
     }

//--- Inicializar símbolo
   if(!m_symbol.Name(Symbol()))
     {
      Print("ERROR: No se pudo inicializar información del símbolo");
      return(INIT_FAILED);
     }

//--- Crear indicadores
   h_MA_slow = iMA(Symbol(), InpTimeframe, InpMAPeriod, 0, MODE_SMA, PRICE_CLOSE);
   h_MA_fast = iMA(Symbol(), InpTimeframe, InpMAFastPeriod, 0, MODE_SMA, PRICE_CLOSE);
   h_ADX     = iADX(Symbol(), InpTimeframe, InpADXPeriod);
   h_ATR     = iATR(Symbol(), InpTimeframe, InpATRPeriod);

   if(h_MA_slow == INVALID_HANDLE || h_MA_fast == INVALID_HANDLE ||
      h_ADX == INVALID_HANDLE || h_ATR == INVALID_HANDLE)
     {
      Print("ERROR: No se pudieron crear los indicadores");
      return(INIT_FAILED);
     }

//--- Configurar arrays como series
   ArraySetAsSeries(g_maSlowBuf, true);
   ArraySetAsSeries(g_maFastBuf, true);
   ArraySetAsSeries(g_adxBuf, true);
   ArraySetAsSeries(g_atrBuf, true);

//--- Configurar trade
   m_trade.SetExpertMagicNumber(InpMagicNumber);
   m_trade.SetMarginMode();
   m_trade.SetTypeFillingBySymbol(Symbol());
   m_trade.SetDeviationInPoints(30);  // Slippage permitido

//--- Estado inicial
   g_initialBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   g_currentStage = STAGE_UNDEFINED;
   g_prevStage = STAGE_UNDEFINED;
   g_lastBarTime = 0;

   Print("═══════════════════════════════════════════════════");
   Print("  Weinstein Stage Analysis EA v1.00");
   Print("  Símbolo: ", Symbol(), " | TF: ", EnumToString(InpTimeframe));
   Print("  MA Lenta: ", InpMAPeriod, " | MA Rápida: ", InpMAFastPeriod);
   Print("  Dirección: ", EnumToString(InpDirection));
   Print("  Riesgo/Trade: ", InpRiskPercent, "%");
   Print("  ATR Stop: ", InpATRMultiplier, "x | ATR Trail: ", InpTrailATRMult, "x");
   Print("  Balance inicial: ", g_initialBalance);
   Print("═══════════════════════════════════════════════════");

   return(INIT_SUCCEEDED);
  }

//+------------------------------------------------------------------+
//| Expert deinitialization function                                  |
//+------------------------------------------------------------------+
void OnDeinit(const int reason)
  {
   if(h_MA_slow != INVALID_HANDLE)  IndicatorRelease(h_MA_slow);
   if(h_MA_fast != INVALID_HANDLE)  IndicatorRelease(h_MA_fast);
   if(h_ADX != INVALID_HANDLE)      IndicatorRelease(h_ADX);
   if(h_ATR != INVALID_HANDLE)      IndicatorRelease(h_ATR);

   double finalBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   double pnl = finalBalance - g_initialBalance;
   Print("═══════════════════════════════════════════════════");
   Print("  EA detenido. P&L: ", DoubleToString(pnl, 2));
   Print("  Balance final: ", DoubleToString(finalBalance, 2));
   Print("═══════════════════════════════════════════════════");
  }

//+------------------------------------------------------------------+
//| Expert tick function                                              |
//+------------------------------------------------------------------+
void OnTick()
  {
//--- Solo operar en nueva barra (D1 = 1 barra por día)
   if(!IsNewBar())
      return;

//--- Verificar drawdown máximo
   if(CheckMaxDrawdown())
     {
      Print("ALERTA: Drawdown máximo alcanzado (", InpMaxDrawdownPct, "%). EA pausado.");
      return;
     }

//--- Filtro horario (solo si está habilitado y TF < D1)
   if(InpUseTimeFilter && InpTimeframe < PERIOD_D1)
     {
      MqlDateTime dt;
      TimeCurrent(dt);
      if(dt.hour < InpStartHour || dt.hour >= InpEndHour)
         return;
     }

//--- Actualizar datos de indicadores
   if(!UpdateIndicators())
      return;

//--- Clasificar etapa actual
   g_prevStage = g_currentStage;
   g_currentStage = ClassifyStage();

//--- Log de cambio de etapa
   if(g_currentStage != g_prevStage && g_prevStage != STAGE_UNDEFINED)
     {
      Print(">>> CAMBIO DE ETAPA: ", StageToString(g_prevStage),
            " → ", StageToString(g_currentStage));
     }

//--- Gestionar posiciones abiertas (trailing stop, salida por cambio de etapa)
   ManageOpenPositions();

//--- Buscar nuevas entradas
   CheckForEntry();
  }

//+------------------------------------------------------------------+
//| Detectar nueva barra                                              |
//+------------------------------------------------------------------+
bool IsNewBar()
  {
   datetime currentBarTime = iTime(Symbol(), InpTimeframe, 0);
   if(currentBarTime == 0)
      return false;

   if(currentBarTime != g_lastBarTime)
     {
      g_lastBarTime = currentBarTime;
      return true;
     }
   return false;
  }

//+------------------------------------------------------------------+
//| Actualizar buffers de indicadores                                 |
//+------------------------------------------------------------------+
bool UpdateIndicators()
  {
   int barsNeeded = InpSlopePeriod + 5;

   if(CopyBuffer(h_MA_slow, 0, 0, barsNeeded, g_maSlowBuf) < barsNeeded)
      return false;
   if(CopyBuffer(h_MA_fast, 0, 0, barsNeeded, g_maFastBuf) < barsNeeded)
      return false;
   if(CopyBuffer(h_ADX, 0, 0, 3, g_adxBuf) < 3)
      return false;
   if(CopyBuffer(h_ATR, 0, 0, 3, g_atrBuf) < 3)
      return false;

   return true;
  }

//+------------------------------------------------------------------+
//| CLASIFICADOR DE ETAPAS (corazón del sistema)                      |
//|                                                                  |
//| Esto es una SIMPLIFICACIÓN del análisis de Weinstein.            |
//| El real requiere: evaluación visual de bases, calidad de          |
//| resistencia, análisis sectorial top-down, y volumen de bolsa.    |
//| Aquí usamos: pendiente de MA + posición del precio + MA cross.   |
//+------------------------------------------------------------------+
ENUM_STAGE ClassifyStage()
  {
   if(ArraySize(g_maSlowBuf) < InpSlopePeriod + 1)
      return STAGE_UNDEFINED;

   double currentMA    = g_maSlowBuf[0];
   double prevMA       = g_maSlowBuf[InpSlopePeriod];
   double currentPrice = iClose(Symbol(), InpTimeframe, 0);

   if(currentMA == 0 || prevMA == 0)
      return STAGE_UNDEFINED;

//--- Calcular pendiente de la MA (cambio porcentual sobre N barras)
   double slope = (currentMA - prevMA) / prevMA;

//--- Posición del precio relativa a la MA
   double priceToMA = (currentPrice - currentMA) / currentMA;

//--- Definir umbrales
   double slopeFlat = InpMinSlope;  // Por debajo de esto, la MA está "plana"

//--- Clasificación por máquina de estados
//    La lógica busca combinar pendiente + posición del precio

   // ETAPA 2 (Avance): MA subiendo + precio por encima
   if(slope > slopeFlat && priceToMA > 0)
      return STAGE_2_ADVANCING;

   // ETAPA 4 (Declive): MA bajando + precio por debajo
   if(slope < -slopeFlat && priceToMA < 0)
      return STAGE_4_DECLINING;

   // ETAPA 1 (Acumulación): MA plana o girando + precio cerca de MA desde abajo
   if(MathAbs(slope) <= slopeFlat && priceToMA > -0.03 && priceToMA < 0.03)
     {
      // Si venimos de Etapa 4, es acumulación
      if(g_prevStage == STAGE_4_DECLINING || g_prevStage == STAGE_1_ACCUMULATION)
         return STAGE_1_ACCUMULATION;
     }

   // ETAPA 3 (Distribución): MA aplanándose + precio oscilando alrededor
   if(MathAbs(slope) <= slopeFlat && priceToMA > -0.03 && priceToMA < 0.03)
     {
      // Si venimos de Etapa 2, es distribución
      if(g_prevStage == STAGE_2_ADVANCING || g_prevStage == STAGE_3_DISTRIBUTION)
         return STAGE_3_DISTRIBUTION;
     }

   // Si MA sube pero precio está debajo (pullback en uptrend?)
   if(slope > slopeFlat && priceToMA < 0 && priceToMA > -0.05)
      return STAGE_2_ADVANCING;  // Aún en avance, solo pullback

   // Si MA baja pero precio está arriba (rally en downtrend?)
   if(slope < -slopeFlat && priceToMA > 0 && priceToMA < 0.05)
      return STAGE_4_DECLINING;  // Aún en declive, solo rebote

//--- Por defecto, mantener etapa anterior
   if(g_prevStage != STAGE_UNDEFINED)
      return g_prevStage;

   return STAGE_UNDEFINED;
  }

//+------------------------------------------------------------------+
//| Verificar condiciones de entrada                                  |
//+------------------------------------------------------------------+
void CheckForEntry()
  {
//--- No abrir más trades si ya tenemos el máximo
   if(CountMyPositions() >= InpMaxOpenTrades)
      return;

//--- Verificar condiciones LONG
   if(InpDirection != MODE_SHORT_ONLY && ShouldEnterLong())
     {
      ExecuteLong();
      return;
     }

//--- Verificar condiciones SHORT
   if(InpDirection != MODE_LONG_ONLY && ShouldEnterShort())
     {
      ExecuteShort();
      return;
     }
  }

//+------------------------------------------------------------------+
//| Condiciones para entrada LONG                                     |
//|                                                                  |
//| Weinstein original: Etapa 1→2 breakout con volumen 2x+           |
//| Nuestra versión: Precio > MA200 + MA subiendo + volumen alto     |
//|                  + ADX confirma tendencia + MA50 > MA200          |
//+------------------------------------------------------------------+
bool ShouldEnterLong()
  {
//--- 1. Estamos en Etapa 2 (avance)
   if(g_currentStage != STAGE_2_ADVANCING)
      return false;

//--- 2. Acabamos de entrar a Etapa 2 (transición reciente) O primera barra en Stage 2
   //    Permitimos entrada mientras estemos en Stage 2 sin posición
   if(HasOpenPosition(POSITION_TYPE_BUY))
      return false;

//--- 3. Precio por encima de la MA lenta
   double currentPrice = iClose(Symbol(), InpTimeframe, 0);
   if(currentPrice <= g_maSlowBuf[0])
      return false;

//--- 4. Golden Cross (MA50 > MA200) si está requerido
   if(InpRequireGoldenCross && g_maFastBuf[0] <= g_maSlowBuf[0])
      return false;

//--- 5. ADX confirma tendencia direccional
   if(g_adxBuf[0] < InpADXMinLevel)
      return false;

//--- 6. Confirmación de volumen (tick volume como proxy)
   //    CAVEAT: Tick volume en CFDs NO es volumen real de bolsa.
   //    Es un proxy imperfecto pero es lo mejor disponible en MT5 para CFDs.
   if(!CheckVolumeConfirmation())
      return false;

//--- 7. La barra actual es alcista (cierre > apertura) - filtro adicional
   double open1  = iOpen(Symbol(), InpTimeframe, 1);
   double close1 = iClose(Symbol(), InpTimeframe, 1);
   if(close1 <= open1)
      return false;  // Queremos una vela alcista confirmando

   return true;
  }

//+------------------------------------------------------------------+
//| Condiciones para entrada SHORT                                    |
//|                                                                  |
//| NOTA HONESTA: Los shorts en trend-following históricamente        |
//| NO generan ganancias sostenibles a largo plazo. Sirven como       |
//| "seguro contra crisis" (2008, 2020, 2022). Usarlos con tamaño   |
//| reducido (50% del largo) y solo en Stage 4 confirmado.           |
//+------------------------------------------------------------------+
bool ShouldEnterShort()
  {
//--- 1. Estamos en Etapa 4 (declive)
   if(g_currentStage != STAGE_4_DECLINING)
      return false;

//--- 2. No hay posición short abierta
   if(HasOpenPosition(POSITION_TYPE_SELL))
      return false;

//--- 3. Precio por debajo de la MA lenta
   double currentPrice = iClose(Symbol(), InpTimeframe, 0);
   if(currentPrice >= g_maSlowBuf[0])
      return false;

//--- 4. Death Cross (MA50 < MA200)
   if(g_maFastBuf[0] >= g_maSlowBuf[0])
      return false;

//--- 5. ADX confirma tendencia
   if(g_adxBuf[0] < InpADXMinLevel)
      return false;

//--- 6. Weinstein: breakdowns NO requieren confirmación de volumen
   //    (a diferencia de breakouts alcistas)

//--- 7. Vela bajista confirmando
   double open1  = iOpen(Symbol(), InpTimeframe, 1);
   double close1 = iClose(Symbol(), InpTimeframe, 1);
   if(close1 >= open1)
      return false;

   return true;
  }

//+------------------------------------------------------------------+
//| Confirmación de volumen                                           |
//+------------------------------------------------------------------+
bool CheckVolumeConfirmation()
  {
   long volumes[];
   ArraySetAsSeries(volumes, true);

   if(CopyTickVolume(Symbol(), InpTimeframe, 0, InpVolAvgPeriod + 1, volumes) < InpVolAvgPeriod + 1)
      return true;  // Si no hay datos, no filtrar

//--- Calcular promedio de volumen (excluyendo barra actual)
   double avgVolume = 0;
   for(int i = 1; i <= InpVolAvgPeriod; i++)
      avgVolume += (double)volumes[i];
   avgVolume /= InpVolAvgPeriod;

//--- Volumen actual debe ser >= multiplicador * promedio
   if(avgVolume == 0)
      return true;

   return ((double)volumes[0] >= avgVolume * InpVolMultiplier);
  }

//+------------------------------------------------------------------+
//| Ejecutar entrada LONG                                             |
//+------------------------------------------------------------------+
void ExecuteLong()
  {
   m_symbol.RefreshRates();
   double ask = m_symbol.Ask();
   if(ask == 0) return;

//--- Calcular stop loss
   double atr = g_atrBuf[1];  // ATR de la barra cerrada (evitar look-ahead)
   double stopDistance = atr * InpATRMultiplier;

//--- También considerar swing low reciente (últimas 20 barras)
   double swingLow = FindSwingLow(20);
   double stopFromSwing = ask - swingLow;

//--- Usar el mayor de los dos (más conservador)
   if(swingLow > 0 && stopFromSwing > stopDistance)
      stopDistance = stopFromSwing;

   double sl = NormalizeDouble(ask - stopDistance, m_symbol.Digits());

//--- Calcular tamaño de posición basado en riesgo
   double lotSize = CalculateLotSize(stopDistance, false);
   if(lotSize <= 0) return;

//--- Take profit: NO usar TP fijo (Weinstein dice "let profits run")
   //    El trailing stop se encarga de la salida
   double tp = 0;  // Sin TP fijo - salida por trailing o cambio de etapa

//--- Ejecutar
   string comment = StringFormat("WS|L|S%d|ATR%.1f", (int)g_currentStage, atr);

   if(m_trade.Buy(lotSize, Symbol(), ask, sl, tp, comment))
     {
      Print("═══ LONG EJECUTADO ═══");
      Print("  Precio: ", DoubleToString(ask, m_symbol.Digits()));
      Print("  SL: ", DoubleToString(sl, m_symbol.Digits()),
            " (", DoubleToString(stopDistance / m_symbol.Point(), 0), " pts)");
      Print("  Lotes: ", DoubleToString(lotSize, 2));
      Print("  Etapa: ", StageToString(g_currentStage));
      Print("  ATR: ", DoubleToString(atr, m_symbol.Digits()));
      Print("  ADX: ", DoubleToString(g_adxBuf[0], 1));
     }
   else
     {
      Print("ERROR al abrir LONG: ", m_trade.ResultRetcodeDescription());
     }
  }

//+------------------------------------------------------------------+
//| Ejecutar entrada SHORT                                            |
//+------------------------------------------------------------------+
void ExecuteShort()
  {
   m_symbol.RefreshRates();
   double bid = m_symbol.Bid();
   if(bid == 0) return;

//--- Calcular stop loss
   double atr = g_atrBuf[1];
   double stopDistance = atr * InpATRMultiplier;

//--- Swing high reciente
   double swingHigh = FindSwingHigh(20);
   double stopFromSwing = swingHigh - bid;

   if(swingHigh > 0 && stopFromSwing > stopDistance)
      stopDistance = stopFromSwing;

   double sl = NormalizeDouble(bid + stopDistance, m_symbol.Digits());

//--- Lotes reducidos para shorts (50% por defecto)
   double lotSize = CalculateLotSize(stopDistance, true);
   if(lotSize <= 0) return;

   double tp = 0;  // Sin TP fijo

   string comment = StringFormat("WS|S|S%d|ATR%.1f", (int)g_currentStage, atr);

   if(m_trade.Sell(lotSize, Symbol(), bid, sl, tp, comment))
     {
      Print("═══ SHORT EJECUTADO ═══");
      Print("  Precio: ", DoubleToString(bid, m_symbol.Digits()));
      Print("  SL: ", DoubleToString(sl, m_symbol.Digits()));
      Print("  Lotes: ", DoubleToString(lotSize, 2),
            " (", DoubleToString(InpShortSizeRatio * 100, 0), "% del tamaño largo)");
      Print("  Etapa: ", StageToString(g_currentStage));
     }
   else
     {
      Print("ERROR al abrir SHORT: ", m_trade.ResultRetcodeDescription());
     }
  }

//+------------------------------------------------------------------+
//| Calcular tamaño de posición basado en riesgo porcentual          |
//|                                                                  |
//| Fórmula: Lotes = (Balance * Risk%) / (StopDistance * TickValue)  |
//|                                                                  |
//| NOTA: Para CFDs de commodities y forex, TickValue varía.         |
//| Usamos SymbolInfoDouble para obtener el valor correcto.          |
//+------------------------------------------------------------------+
double CalculateLotSize(double stopDistancePrice, bool isShort)
  {
   double balance    = AccountInfoDouble(ACCOUNT_BALANCE);
   double riskAmount = balance * (InpRiskPercent / 100.0);

//--- Reducir tamaño para shorts
   if(isShort)
      riskAmount *= InpShortSizeRatio;

//--- Obtener tick value y tick size
   double tickSize  = m_symbol.TickSize();
   double tickValue = m_symbol.TickValue();

   if(tickSize == 0 || tickValue == 0 || stopDistancePrice == 0)
     {
      Print("WARN: No se pudo calcular lot size. tickSize=", tickSize,
            " tickValue=", tickValue, " stopDist=", stopDistancePrice);
      return 0;
     }

//--- Calcular lotes
   double stopInTicks = stopDistancePrice / tickSize;
   double riskPerLot  = stopInTicks * tickValue;

   if(riskPerLot == 0)
      return 0;

   double lots = riskAmount / riskPerLot;

//--- Normalizar al step del broker
   double lotStep = m_symbol.LotsStep();
   double minLot  = m_symbol.LotsMin();
   double maxLot  = m_symbol.LotsMax();

   lots = MathFloor(lots / lotStep) * lotStep;
   lots = MathMax(lots, minLot);
   lots = MathMin(lots, maxLot);

//--- Verificar margen disponible
   double marginRequired;
   if(!OrderCalcMargin(isShort ? ORDER_TYPE_SELL : ORDER_TYPE_BUY,
                       Symbol(), lots, m_symbol.Ask(), marginRequired))
     {
      Print("WARN: No se pudo calcular margen requerido");
      return 0;
     }

   double freeMargin = AccountInfoDouble(ACCOUNT_MARGIN_FREE);
   if(marginRequired > freeMargin * 0.8)  // No usar más del 80% del margen libre
     {
      Print("WARN: Margen insuficiente. Requerido: ", marginRequired,
            " Disponible: ", freeMargin);
      // Reducir lotes para caber en margen
      lots = lots * (freeMargin * 0.7) / marginRequired;
      lots = MathFloor(lots / lotStep) * lotStep;
      if(lots < minLot)
         return 0;
     }

   return lots;
  }

//+------------------------------------------------------------------+
//| Gestionar posiciones abiertas                                     |
//+------------------------------------------------------------------+
void ManageOpenPositions()
  {
   for(int i = PositionsTotal() - 1; i >= 0; i--)
     {
      if(!m_position.SelectByIndex(i))
         continue;
      if(m_position.Symbol() != Symbol())
         continue;
      if(m_position.Magic() != InpMagicNumber)
         continue;

      //--- LONG: Salir si etapa cambia a 3 o 4
      if(m_position.PositionType() == POSITION_TYPE_BUY)
        {
         // Salida por cambio de etapa (distribución o declive)
         if(g_currentStage == STAGE_3_DISTRIBUTION || g_currentStage == STAGE_4_DECLINING)
           {
            Print(">>> Cerrando LONG por cambio a ", StageToString(g_currentStage));
            m_trade.PositionClose(m_position.Ticket());
            continue;
           }

         // Trailing stop
         if(InpUseTrailingStop)
            ApplyTrailingStop(m_position.Ticket(), POSITION_TYPE_BUY);
        }

      //--- SHORT: Salir si etapa cambia a 1 o 2
      if(m_position.PositionType() == POSITION_TYPE_SELL)
        {
         if(g_currentStage == STAGE_1_ACCUMULATION || g_currentStage == STAGE_2_ADVANCING)
           {
            Print(">>> Cerrando SHORT por cambio a ", StageToString(g_currentStage));
            m_trade.PositionClose(m_position.Ticket());
            continue;
           }

         if(InpUseTrailingStop)
            ApplyTrailingStop(m_position.Ticket(), POSITION_TYPE_SELL);
        }
     }
  }

//+------------------------------------------------------------------+
//| Trailing stop                                                     |
//|                                                                  |
//| Dos modos:                                                       |
//| 1. ATR-based: Trail a N×ATR del precio actual                    |
//| 2. MA-based: Trail usando la SMA 200 como soporte dinámico       |
//|    (Weinstein original: stop bajo la MA de 30 semanas)           |
//+------------------------------------------------------------------+
void ApplyTrailingStop(ulong ticket, ENUM_POSITION_TYPE posType)
  {
   if(!m_position.SelectByTicket(ticket))
      return;

   double currentSL = m_position.StopLoss();
   double atr = g_atrBuf[1];
   double newSL = 0;

   if(posType == POSITION_TYPE_BUY)
     {
      double currentPrice = m_symbol.Bid();

      // Modo ATR
      double atrTrail = currentPrice - atr * InpTrailATRMult;

      // Modo MA (usar MA como soporte dinámico)
      double maTrail = g_maSlowBuf[0] - atr * 0.5;  // Dar un pequeño buffer bajo la MA

      if(InpTrailUseMA)
         newSL = MathMin(atrTrail, maTrail);  // El más conservador (más cercano al precio)
      else
         newSL = atrTrail;

      newSL = NormalizeDouble(newSL, m_symbol.Digits());

      // Solo mover SL hacia arriba (nunca hacia abajo)
      if(newSL > currentSL && newSL < currentPrice - m_symbol.Spread() * m_symbol.Point())
        {
         if(m_trade.PositionModify(ticket, newSL, m_position.TakeProfit()))
            Print("  Trailing SL LONG → ", DoubleToString(newSL, m_symbol.Digits()));
        }
     }
   else if(posType == POSITION_TYPE_SELL)
     {
      double currentPrice = m_symbol.Ask();

      double atrTrail = currentPrice + atr * InpTrailATRMult;
      double maTrail = g_maSlowBuf[0] + atr * 0.5;

      if(InpTrailUseMA)
         newSL = MathMax(atrTrail, maTrail);
      else
         newSL = atrTrail;

      newSL = NormalizeDouble(newSL, m_symbol.Digits());

      // Solo mover SL hacia abajo
      if((currentSL == 0 || newSL < currentSL) && newSL > currentPrice + m_symbol.Spread() * m_symbol.Point())
        {
         if(m_trade.PositionModify(ticket, newSL, m_position.TakeProfit()))
            Print("  Trailing SL SHORT → ", DoubleToString(newSL, m_symbol.Digits()));
        }
     }
  }

//+------------------------------------------------------------------+
//| Encontrar swing low reciente                                      |
//+------------------------------------------------------------------+
double FindSwingLow(int lookback)
  {
   double low = DBL_MAX;
   for(int i = 1; i <= lookback; i++)
     {
      double barLow = iLow(Symbol(), InpTimeframe, i);
      if(barLow > 0 && barLow < low)
         low = barLow;
     }
   return (low == DBL_MAX) ? 0 : low;
  }

//+------------------------------------------------------------------+
//| Encontrar swing high reciente                                     |
//+------------------------------------------------------------------+
double FindSwingHigh(int lookback)
  {
   double high = 0;
   for(int i = 1; i <= lookback; i++)
     {
      double barHigh = iHigh(Symbol(), InpTimeframe, i);
      if(barHigh > high)
         high = barHigh;
     }
   return high;
  }

//+------------------------------------------------------------------+
//| Verificar drawdown máximo                                         |
//+------------------------------------------------------------------+
bool CheckMaxDrawdown()
  {
   double currentBalance = AccountInfoDouble(ACCOUNT_BALANCE);
   double currentEquity  = AccountInfoDouble(ACCOUNT_EQUITY);

   // Usar el menor entre balance y equity
   double currentValue = MathMin(currentBalance, currentEquity);
   double drawdownPct = ((g_initialBalance - currentValue) / g_initialBalance) * 100.0;

   return (drawdownPct >= InpMaxDrawdownPct);
  }

//+------------------------------------------------------------------+
//| Contar posiciones propias                                         |
//+------------------------------------------------------------------+
int CountMyPositions()
  {
   int count = 0;
   for(int i = PositionsTotal() - 1; i >= 0; i--)
     {
      if(!m_position.SelectByIndex(i))
         continue;
      if(m_position.Symbol() == Symbol() && m_position.Magic() == InpMagicNumber)
         count++;
     }
   return count;
  }

//+------------------------------------------------------------------+
//| Verificar si hay posición abierta de tipo específico              |
//+------------------------------------------------------------------+
bool HasOpenPosition(ENUM_POSITION_TYPE posType)
  {
   for(int i = PositionsTotal() - 1; i >= 0; i--)
     {
      if(!m_position.SelectByIndex(i))
         continue;
      if(m_position.Symbol() == Symbol() && m_position.Magic() == InpMagicNumber
         && m_position.PositionType() == posType)
         return true;
     }
   return false;
  }

//+------------------------------------------------------------------+
//| Convertir etapa a string                                          |
//+------------------------------------------------------------------+
string StageToString(ENUM_STAGE stage)
  {
   switch(stage)
     {
      case STAGE_1_ACCUMULATION: return "S1-Acumulación";
      case STAGE_2_ADVANCING:    return "S2-Avance";
      case STAGE_3_DISTRIBUTION: return "S3-Distribución";
      case STAGE_4_DECLINING:    return "S4-Declive";
      default:                   return "Indefinido";
     }
  }

//+------------------------------------------------------------------+
//| GUÍA DE BACKTESTING (lee esto antes de optimizar)                 |
//|                                                                  |
//| 1. PRIMERO: Backtest con parámetros DEFAULT en XAUUSD D1         |
//|    - Período: mínimo 3-5 años (2021-2026)                        |
//|    - Modelo: Every tick based on real ticks                       |
//|    - Spread: Current o "Specified spread" del broker real         |
//|                                                                  |
//| 2. EVALUAR: ¿Es viable?                                          |
//|    - Profit Factor > 1.3  → Viable                               |
//|    - Profit Factor > 1.5  → Bueno                                |
//|    - Profit Factor > 2.0  → Sospechoso (verificar)               |
//|    - Win Rate 30-50%      → Normal para trend-following           |
//|    - Max DD < 20%         → Aceptable                            |
//|    - Min 30+ trades       → Mínimo estadístico                   |
//|                                                                  |
//| 3. STRESS TEST (NO optimizar para máximo profit):                 |
//|    - Variar MA: 150, 175, 200, 225, 250                          |
//|    - Variar ATR mult: 2.0, 2.5, 3.0                              |
//|    - Variar ADX: 15, 20, 25                                      |
//|    - Si TODOS son rentables → edge real (meseta estable)          |
//|    - Si solo ALGUNOS → curve-fitting (peligro)                    |
//|                                                                  |
//| 4. OTROS ACTIVOS a probar (en orden de probabilidad de éxito):   |
//|    - XAGUSD D1 (plata - tiende fuerte)                           |
//|    - WTI/USOIL D1 (petróleo - muy volátil)                       |
//|    - US500 D1 (S&P 500 - más mean-reverting)                     |
//|    - NAS100 D1 (Nasdaq - tech heavy, actualmente en Stage 3-4)   |
//|    - USDJPY D1 (el "mejor" par forex para trending)              |
//|                                                                  |
//| 5. TEMPORALIDADES alternativas:                                   |
//|    - W1 con MA 40: Más fiel a Weinstein, menos señales           |
//|    - H4 con MA 900+: Mucho ruido, no recomendado                 |
//|    - H1 o menor: Expectativa NEGATIVA demostrada en backtests    |
//|                                                                  |
//| 6. RED FLAGS en resultados:                                       |
//|    - Win rate > 60% → Probablemente algo está mal                |
//|    - 0 trades → Filtros demasiado restrictivos                   |
//|    - 500+ trades en 5 años (D1) → Algo genera señales falsas    |
//|    - Profit concentrado en 1-2 meses → No es edge sostenible     |
//+------------------------------------------------------------------+

